	/**//*C  C*/ function  update_day_change()
	{
		/*update day_change from today and yesterday's close*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: */
		/*	Use Case When: */
		/*	Use Case What: */
		/*	Use Case Why: */
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		$this->querystring = "update stockprices a, stockprices b
		set
		        a.day_change = (a.day_close - b.day_close)
		where
		        a.symbol = b.symbol
		        and a.date = b.date + 1
		        and a.day_change = '0'";
		$this->GenericQuery();
		return SUCCESS;
		//If we don't have a return in the body in codemeta, return
		return ;
	}
