	/*********************************************************************
	*	@function closehigherthan20high
	*	@param $symbol, $date
	*	@see 
	*	@return BOOL
	*********************************************************************/
	/*BOOL*//*C BOOL C*/ function  closehigherthan20high($symbol, $date)
	{
		/*Check to see if the close is higher than the 20 day high*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: system*/
		/*	Use Case When: Analysis of stock prices*/
		/*	Use Case What: 4 week rule*/
		/*	Use Case Why: 20 trading day cycle is a well recognized one*/
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		        //Check to see if the symbol's closing price on a given
		        //date is higher than the high of the last 20 days
		        $this->Setsymbol( $symbol );
		        $this->Setdate( $date );
		        $this->setValues();
		        $close = $this->Getday_close();
		        $high20 = floor( $this->highprice20() );
		        echo "High $high20 Close $close\n";
		        if( $close >= $high20 )
		                return TRUE;
		//If we don't have a return in the body in codemeta, return
		return FALSE;
	}
	/*********************************************************************
	*	@function closelowerthan20low
	*	@param $symbol, $date
	*	@see 
	*	@return BOOL
	*********************************************************************/
	/*BOOL*//*C BOOL C*/ function  closelowerthan20low($symbol, $date)
	{
		/*compare the price to the previous 20 lows*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: system*/
		/*	Use Case When: price analysis*/
		/*	Use Case What: check for close being lower than 20 day low*/
		/*	Use Case Why: well known cycle*/
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		//Check to see if the symbol's closing price on a given
		        //date is lower than the low of the last 20 days
		        //One issue is if there is no data for that date for the symbol, this returns TRUE.
		        $this->Setsymbol( $symbol );
		        $this->Setdate( $date );
		        $this->setValues();
		        $close = $this->Getday_close();
		        if( $close < 0.01 )
		              return FALSE; //see above re no data.
		        $low20 = ceil( $this->lowprice20() );
		        echo "Low $low20 Close $close\n";
		        if( $close < $low20 )
		                return TRUE;
		
		//If we don't have a return in the body in codemeta, return
		return FALSE;
	}
