	/*date*//*C date C*/ function  Getnexttradedate()
	{
		/*Retrieve the next date that the stock traded*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: system*/
		/*	Use Case When: searching for trade dates*/
		/*	Use Case What: return the next date after the set date*/
		/*	Use Case Why: to simulate the next day purchase*/
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		//Assumes that symbol, date is already set
		$this->select = "date";
		$this->orderby = "date asc";
		$this->where = "date > '" . $this->Getdate() . "' and symbol = '" . $this->Getsymbol() . "'";
		$this->limit = 1;
		$this->Select();
		if( isset( $this->resultarray[0]['date'] ))
		return $this->resultarray[0]['date'];
		
