	/*float*//*C float C*/ function  getcloseprice($symbol, $transactiondate)
	{
		/*Get the closing price for a day*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: system*/
		/*	Use Case When: need closing price*/
		/*	Use Case What: return closing price*/
		/*	Use Case Why: */
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		if( !isset( $this->symbol ) OR 0 == strcmp($this->Getsymbol(), "" ) )
		  return NULL;
		if( !isset( $this->transactiondate ) OR 0 == strcmp($this->Gettransactiondate(), "" ) )
		  return NULL;
		$this->Setsymbol( $symbol );
		$this->Settransactiondate( $transactiondate);
		$this->GetVARRow();
		
		//If we don't have a return in the body in codemeta, return
		return $this->Getday_close();
	}
